const task = $('Start').item.json;
const phaseRows = $('Load All Phases').all();
const fs = require('fs');

const phases = {};
phaseRows.forEach(row => {
  phases[row.json.phase_id] = row.json.output_json;
});

const p0a = phases.phase_0a || {};
const p0b = phases.phase_0b || {};
const p1  = phases.phase_1  || {};
const p2  = phases.phase_2  || {};
const p3  = phases.phase_3  || {};
const p4  = phases.phase_4  || {};
const p5  = phases.phase_5  || {};
const p6  = phases.phase_6  || {};
const p7  = phases.phase_7  || {};

let md = [];

// HEADER
md.push(`# NETS Uy Vazifasi — Matematika, ${task.grade}-sinf, 1-mavzu`);
md.push(`**Fan:** Matematika | **Sinf:** ${task.grade} | **Til:** ${task.lang} | **Maqsad:** PISA L1→L2 | **Boss HP:** 100 | **Vaqt:** 25-35 daqiqa`);
md.push('');

// PHASE 0-A
md.push('---');
md.push('## PHASE 0-A: MAVZU KO\'RIGI / Theme Preview');
if (p0a.gate_quote) {
  md.push(`> *"${p0a.gate_quote.text}"* — ${p0a.gate_quote.author}`);
  md.push('*(5 soniya kutiladi...)*');
  md.push('');
}
(p0a.panels || []).forEach(panel => {
  md.push(`### ${panel.panel_number}-panel: ${panel.title}`);
  md.push(panel.content);
  md.push('');
});
if (p0a.bost_goal) {
  md.push(`**📌 Bugungi Maqsad:** ${p0a.bost_goal}`);
  md.push('');
}

// PHASE 0-B
md.push('---');
md.push('## PHASE 0-B: FLASH KARTALAR / Flash Cards');
(p0b.cards || []).forEach(card => {
  const icon = card.card_type === 'mistake' ? '⚠️' : '📋';
  md.push(`- ${icon} **${card.front_text}** → ${card.back_text}`);
});
md.push('');
md.push('**[ MENING UY VAZIFAMNI BOSHLASH ]**');
md.push('');

// PHASE 1
md.push('---');
md.push('## PHASE 1: XOTIRA SPRINTI / Memory Sprint');
md.push('*≤2 daqiqa · Faqat bosish*');
md.push('');
(p1.items || []).forEach(item => {
  md.push(`${item.item_number}. ${item.question_text} ${item.tag || '[Bloom: L1 | PISA: L1]'}`);
  if (item.options) {
    item.options.forEach((opt, i) => md.push(`   ${String.fromCharCode(65+i)}) ${opt}`));
  }
  md.push(`   **✅ Javob:** ${item.correct_answer}`);
  if (item.wrong_answer_feedback) md.push(`   *${item.wrong_answer_feedback}*`);
  md.push('');
});

// PHASE 2
md.push('---');
md.push('## PHASE 2: HIKOYA REJIMI / Story Mode');
md.push('*5-7 daqiqa*');
md.push('');
(p2.segments || []).forEach(seg => {
  md.push(seg.narrative_text);
  md.push('');
  if (seg.checkpoint) {
    const cp = seg.checkpoint;
    md.push(`**Savol:** ${cp.question} ${cp.tag || '[Bloom: L1-L2 | PISA: L1-L2]'}`);
    if (cp.options) cp.options.forEach((o,i) => md.push(`${String.fromCharCode(65+i)}) ${o}`));
    md.push(`**✅ Javob:** ${cp.correct_answer}`);
    md.push(`*${cp.explanation}*`);
    md.push('');
  }
});

// PHASE 3
md.push('---');
md.push('## PHASE 3: O\'YIN TANAFFUSLARI / Game Breaks');
md.push('*6-9 daqiqa · 3 ta o\'yin*');
md.push('');
(p3.games || []).forEach(game => {
  md.push(`### ${game.slot}-o'yin: ${game.game_name}`);
  (game.items || []).forEach(item => {
    if (item.question_or_prompt) {
      md.push(`${item.item_number}. ${item.question_or_prompt} ${item.tag || '[Bloom: L1-L3 | PISA: L1-L2]'}`);
    } else if (item.left_item) {
      md.push(`${item.pair_number}. ${item.left_item} ↔ ${item.right_item}`);
    }
    if (item.correct_answer) md.push(`   **✅ Javob:** ${item.correct_answer}`);
    md.push('');
  });
});

// PHASE 4
md.push('---');
md.push('## PHASE 4: HAYOTIY VAZIFA / Real-Life Challenge');
md.push('*3-5 daqiqa*');
md.push('');
if (p4.scenario_text) md.push(p4.scenario_text + '\n');
if (p4.w5h_scaffold) {
  const w = p4.w5h_scaffold;
  md.push('**W5H:**');
  if (w.who) md.push(`- **Kim:** ${w.who}`);
  if (w.what) md.push(`- **Nima:** ${w.what}`);
  if (w.where) md.push(`- **Qayerda:** ${w.where}`);
  if (w.why) md.push(`- **Nima uchun:** ${w.why}`);
  if (w.how) md.push(`- **Qanday:** ${w.how}`);
  md.push('');
}
(p4.questions || []).forEach(q => {
  md.push(`${q.question_number}. ${q.question_text} ${q.tag || '[Bloom: L3-L4 | PISA: L2-L3]'}`);
  if (q.wise_status_text) md.push(`   *${q.wise_status_text}*`);
  md.push(`   **✅ Javob:** ${q.correct_answer}`);
  md.push('');
});

// PHASE 5
md.push('---');
md.push('## PHASE 5: MUSTAHKAMLASH / Consolidation');
md.push('*2-3 daqiqa · Baholanmaydi*');
md.push('');
if (p5.formula_warmup) {
  md.push(`**Formula tekshiruvi:** ${p5.formula_warmup.formula_shown}`);
  md.push('');
}
if (p5.technique_chosen) md.push(`**Usul:** ${p5.technique_chosen} — ${p5.technique_rationale || ''}`);
if (p5.mnemonic_exercise) md.push('\n' + p5.mnemonic_exercise);
md.push('');

// PHASE 6
md.push('---');
md.push('## PHASE 6: YAKUNIY BOSS / Final Boss');
md.push(`*Boss HP: ${p6.boss_hp || 100} · 5-10 daqiqa*`);
md.push('');
(p6.questions || []).forEach(q => {
  md.push(`${q.question_number}. [${q.difficulty?.toUpperCase()} | ${q.damage_hp} HP] ${q.question_text} ${q.tag || ''}`);
  md.push(`   *Yordam: ${q.hint_text}*`);
  md.push(`   **✅ Javob:** ${q.correct_answer}`);
  if (q.rubric) {
    md.push(`   *Rubrika: To'liq=${q.rubric.full_credit} | Qisman=${q.rubric.partial_credit}*`);
  }
  md.push('');
});

// PHASE 7
md.push('---');
md.push('## PHASE 7: FIKRLASH / Reflection');
md.push('*2-3 daqiqa*');
md.push('');
if (p7.session_summary) {
  md.push('**Bugungi asosiy o\'rganishlar:**');
  p7.session_summary.forEach(s => md.push(`- ${s}`));
  md.push('');
}
if (p7.bost_recall) {
  md.push(`**📌 Maqsad yodga olish:** ${p7.bost_recall}`);
  md.push('');
}
(p7.reflection_prompts || []).forEach(p => {
  const text = typeof p === 'string' ? p : p.prompt_text;
  md.push(`${p.prompt_number || '•'}. ${text}`);
});
md.push('');
if (p7.spaced_rep_schedule) {
  const s = p7.spaced_rep_schedule;
  md.push(`**Qayta ko'rish jadvali:** ${s.day1} → ${s.day3} → ${s.day7} → ${s.day21}`);
}
if (p7.third_renaissance_closing) {
  md.push('');
md.push(`*${p7.third_renaissance_closing}*`);
}

const finalMd = md.join('\n');
const mdPath = `/home/node/nets/nets-output/${task.lesson_id}_homework.md`;

return [{ json: { md_content: finalMd, md_path: mdPath, task_id: task.task_id, lesson_id: task.lesson_id } }];
